from functools import lru_cache

def lcs_length(a, b):
    # dynamic programming O(n*m) fairly heavy but strings are short; ok
    n, m = len(a), len(b)
    dp = [0] * (m+1)
    for i in range(1, n+1):
        prev = 0
        for j in range(1, m+1):
            temp = dp[j]
            if a[i-1] == b[j-1]:
                dp[j] = prev + 1
            else:
                if dp[j] < dp[j-1]:
                    dp[j] = dp[j-1]
            prev = temp
    return dp[m]

def lcs_ratio(a, b):
    if not a or not b: 
        return 0.0
    L = lcs_length(a, b)
    return L / max(len(a), len(b))

def token_f1(a, b):
    # tokens splitting by space
    ta = a.split()
    tb = b.split()
    if not ta or not tb:
        return 0.0
    # Use set-based? But repeated tokens matter? We'll do multiset intersection counting frequency
    from collections import Counter
    ca = Counter(ta)
    cb = Counter(tb)
    common = sum((ca & cb).values())
    prec = common / len(tb)  # predicted tokens b vs a? Actually whichever; We compute symmetrical F1
    rec = common / len(ta)
    if prec+rec == 0: return 0.0
    return 2*prec*rec/(prec+rec)

